// Each chain gets its OWN DexScreener search URL
// Using /dex/search to find latest tokens per chain
return [
  {
    json: {
      chain: 'ethereum',
      chainId: '1',
      goplusChainId: '1',
      explorerKey: 'UR93BU1IYNAYCW2H825UP1X9UAQTBS6J1I',
      minLiquidity: 500,
      dexSearchUrl: 'https://api.dexscreener.com/latest/dex/search?q=ethereum'
    }
  },
  {
    json: {
      chain: 'bsc',
      chainId: '56',
      goplusChainId: '56',
      explorerKey: 'UR93BU1IYNAYCW2H825UP1X9UAQTBS6J1I',
      minLiquidity: 300,
      dexSearchUrl: 'https://api.dexscreener.com/latest/dex/search?q=bsc'
    }
  },
  {
    json: {
      chain: 'solana',
      chainId: 'solana',
      goplusChainId: 'solana',
      explorerKey: 'none',
      minLiquidity: 200,
      dexSearchUrl: 'https://api.dexscreener.com/latest/dex/search?q=solana'
    }
  }
];

// Build the DexScreener URL from the chain config item
// Keeps the expression OUT of the HTTP node to avoid rendering bugs
const cfg = $input.item.json;
return [{ json: { ...cfg, fetchUrl: cfg.dexSearchUrl } }];

const cfg   = $('Build Dex URL').item.json;
const chain = cfg.chain;
const minLiq = cfg.minLiquidity || 200;

const raw   = $input.item.json;
const pairs = raw.pairs || [];

const now = Date.now();
const threeDaysMs = 3 * 24 * 60 * 60 * 1000;

// Map chain name to dexscreener chainId values
const chainAliases = {
  ethereum: ['ethereum', 'eth'],
  bsc:      ['bsc', 'bnb', 'binance', 'bsc_mainnet'],
  solana:   ['solana', 'sol']
};
const aliases = chainAliases[chain] || [chain];

const filtered = pairs
  .filter(p => {
    const pChain = (p.chainId || '').toLowerCase();
    const liq    = p.liquidity?.usd || 0;
    const age    = now - (p.pairCreatedAt || 0);
    return aliases.includes(pChain) && liq >= minLiq && age < threeDaysMs;
  })
  .sort((a, b) => (b.pairCreatedAt || 0) - (a.pairCreatedAt || 0))
  .slice(0, 3)
  .map(p => ({
    json: {
      chain,
      chainId:         cfg.chainId,
      goplusChainId:   cfg.goplusChainId,
      explorerKey:     cfg.explorerKey,
      minLiquidity:    minLiq,
      symbol:          p.baseToken?.symbol  || 'UNKNOWN',
      name:            p.baseToken?.name    || 'Unknown Token',
      contractAddress: p.baseToken?.address || '',
      pairAddress:     p.pairAddress        || '',
      dex:             p.dexId              || 'unknown',
      priceUsd:        p.priceUsd           || '0',
      liquidity:       p.liquidity?.usd     || 0,
      volume24h:       p.volume?.h24        || 0,
      priceChange24h:  p.priceChange?.h24   || 0,
      txns24h:         (p.txns?.h24?.buys || 0) + (p.txns?.h24?.sells || 0),
      marketCap:       p.marketCap          || p.fdv || 0,
      pairAgeMinutes:  Math.round((now - (p.pairCreatedAt || now)) / 60000)
    }
  }));

if (filtered.length === 0) {
  // Debug: show what chainIds came back so we can adjust
  const sample = pairs.slice(0, 5).map(p => p.chainId);
  return [{ json: { skip: true, chain, reason: 'No tokens found. Sample chainIds from API: ' + JSON.stringify(sample) } }];
}

return filtered;

// Build GoPlus URL safely in code — no expression issues
const t = $input.item.json;
let url;
if (t.goplusChainId === 'solana') {
  url = 'https://api.gopluslabs.io/api/v1/solana/token_security?contract_addresses=' + encodeURIComponent(t.contractAddress);
} else {
  url = 'https://api.gopluslabs.io/api/v1/token_security/' + t.goplusChainId + '?contract_addresses=' + encodeURIComponent(t.contractAddress);
}
return [{ json: { ...t, goplusFetchUrl: url } }];

const token  = $('Build GoPlus URL').item.json;
const raw    = $input.item.json;

const gpResult = raw?.result || {};
const gpData   = typeof gpResult === 'object'
  ? (Object.values(gpResult)[0] || {})
  : {};

const top10 = (gpData.holders || [])
  .slice(0, 10)
  .reduce((s, h) => s + parseFloat(h.percent || 0), 0)
  .toFixed(2);

return [{ json: {
  ...token,
  is_honeypot:             gpData.is_honeypot             || '0',
  buy_tax:                 gpData.buy_tax                 || '0',
  sell_tax:                gpData.sell_tax                || '0',
  is_mintable:             gpData.is_mintable             || '0',
  can_take_back_ownership: gpData.can_take_back_ownership || '0',
  hidden_owner:            gpData.hidden_owner            || '0',
  is_blacklisted:          gpData.is_blacklisted          || '0',
  is_proxy:                gpData.is_proxy                || '0',
  lp_locked:               gpData.lp_holder_analysis?.[0]?.is_locked || '0',
  holder_count:            gpData.holder_count            || '0',
  top10_holder_ratio:      top10,
  sol_mintable:            gpData.mintable                || false,
  sol_freeze_authority:    gpData.freezeable              || false
}}];

const inp = $input.item.json;
let raw = inp.text || inp.output || inp.content || '';
if (!raw && inp.generations) raw = inp.generations?.[0]?.[0]?.text || '';
if (!raw) raw = JSON.stringify(inp);

raw = raw.replace(/```json/gi, '').replace(/```/gi, '').trim();
const m = raw.match(/\{[\s\S]*\}/);
raw = m ? m[0] : raw;

let ai;
try { ai = JSON.parse(raw); }
catch(e) {
  ai = {
    chain: 'unknown', token: 'UNKNOWN', contract: '',
    scores: { tokenomics: 50, contract: 50, sentiment: 50, liquidity: 50, overall: 50 },
    verdict: 'CAUTION',
    flags: ['AI parse error - review manually'],
    summary: 'Could not parse AI response.',
    recommendation: 'MONITOR'
  };
}

const t = $('Merge Security Data').item.json;
const chainMod = { ethereum: 5, bsc: -5, solana: -3 }[t.chain] || 0;

let cs = ai.scores?.contract ?? 50;
if (t.is_honeypot === '1')               cs -= 50;
if (parseFloat(t.buy_tax)  > 10)         cs -= 20;
if (parseFloat(t.sell_tax) > 10)         cs -= 20;
if (t.can_take_back_ownership === '1')   cs -= 15;
if (t.hidden_owner === '1')              cs -= 15;
if (t.is_mintable === '1')               cs -= 20;
if (t.is_proxy === '1')                  cs -= 10;
if (t.chain === 'solana' && t.sol_mintable)          cs -= 25;
if (t.chain === 'solana' && t.sol_freeze_authority)  cs -= 15;
cs = Math.max(0, cs);

let ls = ai.scores?.liquidity ?? 50;
if (t.liquidity < t.minLiquidity) ls -= 25;
if (t.lp_locked === '1')          ls += 15;
const vmr = t.marketCap > 0 ? t.volume24h / t.marketCap : 0;
if (vmr > 2) ls -= 10;
ls = Math.max(0, Math.min(100, ls));

const rawScore = Math.round(
  (ai.scores?.tokenomics ?? 50) * 0.25 +
   cs                           * 0.35 +
  (ai.scores?.sentiment  ?? 50) * 0.15 +
   ls                           * 0.25
);
const overall = Math.max(0, Math.min(100, rawScore + chainMod));

const verdict    = overall >= 70 ? 'SAFE' : overall >= 50 ? 'CAUTION' : 'DANGER';
const vEmoji     = { SAFE: '✅', CAUTION: '⚡', DANGER: '🚨' }[verdict];
const chainLabel = { ethereum: '⬡ ETH', bsc: '◈ BSC', solana: '◎ SOL' }[t.chain] || t.chain.toUpperCase();
const rec        = overall >= 70 ? 'BUY_WATCH' : overall >= 50 ? 'MONITOR' : 'AVOID';
const flags      = (ai.flags || []).slice(0, 6);
const flagLines  = flags.length ? flags.map(f => '⚠️ ' + f).join('\n') : '✅ No critical flags';

const tgMsg =
  '🔔 <b>' + chainLabel + ' — NEW TOKEN</b>\n' +
  '━━━━━━━━━━━━━━━━━━\n' +
  '<b>Token:</b> $' + (ai.token || t.symbol) + '\n' +
  '<b>Contract:</b> <code>' + t.contractAddress + '</code>\n' +
  '<b>DEX:</b> ' + t.dex + ' · Age: ' + t.pairAgeMinutes + 'm\n\n' +
  '📊 <b>SCORES</b>\n' +
  'Tokenomics : ' + (ai.scores?.tokenomics ?? 50) + '/100\n' +
  'Contract   : ' + cs + '/100\n' +
  'Sentiment  : ' + (ai.scores?.sentiment ?? 50) + '/100\n' +
  'Liquidity  : ' + ls + '/100\n\n' +
  '💰 <b>MARKET</b>\n' +
  'Liquidity  : $' + Number(t.liquidity).toLocaleString() + '\n' +
  'Volume 24h : $' + Number(t.volume24h).toLocaleString() + '\n' +
  'LP Locked  : ' + (t.lp_locked === '1' ? '✅ YES' : '❌ NO') + '\n' +
  'Honeypot   : ' + (t.is_honeypot === '1' ? '🚨 YES' : '✅ NO') + '\n' +
  'Tax B/S    : ' + t.buy_tax + '% / ' + t.sell_tax + '%\n\n' +
  '🚩 <b>FLAGS</b>\n' + flagLines + '\n\n' +
  '📝 ' + (ai.summary || '') + '\n\n' +
  vEmoji + ' <b>VERDICT: ' + verdict + ' · ' + overall + '/100</b>\n' +
  '<b>ACTION: ' + rec + '</b>';

return [{ json: {
  chain: t.chain,
  symbol: ai.token || t.symbol,
  contractAddress: t.contractAddress,
  overall, verdict, recommendation: rec,
  scores: { tokenomics: ai.scores?.tokenomics ?? 50, contract: cs, sentiment: ai.scores?.sentiment ?? 50, liquidity: ls, overall },
  flags, summary: ai.summary || '',
  telegramMsg: tgMsg,
  liquidity: t.liquidity,
  volume24h: t.volume24h,
  marketCap: t.marketCap,
  is_honeypot: t.is_honeypot,
  buy_tax: t.buy_tax,
  sell_tax: t.sell_tax,
  lp_locked: t.lp_locked,
  pairAgeMinutes: t.pairAgeMinutes,
  analyzedAt: new Date().toISOString()
}}];
